module RefModule(
    input [7:0] data_in,
    input load,
    input reset,
    input clock,
    output reg [7:0] data_out
);reg [7:0] unused_reg_value;

always @(posedge clock) begin
    if (reset) begin
        unused_reg_value <= 8'b0;
    end else if (load) begin
        unused_reg_value <= data_in;
    end else begin
        unused_reg_value <= unused_reg_value;
    end
end

assign data_out = unused_reg_value;

endmodule
